eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   AI_NEWS: () => (/* binding */ AI_NEWS),\n/* harmony export */   NEWS_ITEMS: () => (/* binding */ NEWS_ITEMS),\n/* harmony export */   NEWS_TAGS: () => (/* binding */ NEWS_TAGS)\n/* harmony export */ });\nconst AI_NEWS = [\n    // ── 2023 ─────────────────────────────────────────────────────────────────\n    {\n        id: \"bing-chat-launch\",\n        date: \"Feb 2023\",\n        dateNum: 202302,\n        title: \"Microsoft Bing Chat Launches — GPT-4 Meets Search\",\n        summary: \"Microsoft launched Bing Chat powered by an early version of GPT-4 in limited preview, integrating a conversational AI directly into its search engine and Edge browser. The product generated significant press when users discovered the model, codenamed Sydney, would make unusual and emotionally charged claims in extended conversations. Microsoft rapidly limited conversation lengths and adjusted the model's behavior in response.\",\n        tags: [\n            \"Microsoft\",\n            \"Bing\",\n            \"GPT-4\",\n            \"Search\",\n            \"Chatbot\"\n        ],\n        significance: \"major\",\n        provider: \"Microsoft\",\n        providerColor: \"#0078d4\",\n        url: \"https://blogs.microsoft.com/blog/2023/02/07/reinventing-search-with-a-new-ai-powered-microsoft-bing/\"\n    },\n    {\n        id: \"llama-1-leak\",\n        date: \"Mar 2023\",\n        dateNum: 202303,\n        title: \"LLaMA-1 Leaks Online — Open-Weight Era Begins\",\n        summary: \"Meta's LLaMA-1 models (7B–65B parameters), initially shared only with select researchers, leaked publicly within days and triggered an immediate wave of community fine-tuning that produced models like Alpaca and Vicuna within weeks. The leak effectively democratized access to frontier-class open weights overnight. It ignited the open-source LLM ecosystem that would grow into thousands of derivative projects over the following two years.\",\n        tags: [\n            \"Meta\",\n            \"LLaMA\",\n            \"Open Source\",\n            \"Open Weights\",\n            \"Community\"\n        ],\n        significance: \"landmark\",\n        provider: \"Meta\",\n        providerColor: \"#0866ff\",\n        url: \"https://ai.meta.com/blog/large-language-model-llama-meta-ai/\"\n    },\n    {\n        id: \"gpt-4-launch\",\n        date: \"Mar 2023\",\n        dateNum: 202303,\n        title: \"GPT-4 Released — Professional-Grade Multimodal AI\",\n        summary: \"OpenAI released GPT-4, the first frontier large language model capable of processing both text and images as inputs. It scored in the 90th percentile on the bar exam, 99th percentile on the GRE verbal, and outperformed GPT-3.5 substantially across professional and academic benchmarks. Enterprises across law, medicine, education, and finance began integrating it within weeks of launch.\",\n        tags: [\n            \"OpenAI\",\n            \"GPT-4\",\n            \"Multimodal\",\n            \"Benchmark\",\n            \"Professional\"\n        ],\n        significance: \"landmark\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://openai.com/index/gpt-4/\"\n    },\n    {\n        id: \"claude-1\",\n        date: \"Mar 2023\",\n        dateNum: 202303,\n        title: \"Anthropic Launches Claude — Constitutional AI in Production\",\n        summary: \"Anthropic released Claude, its first publicly available model, trained using Constitutional AI — a technique where a set of written principles guides model behavior rather than relying purely on human feedback labels. Claude was noted for a longer context window than GPT-3.5 and a cautious, thoughtful conversational style. It was made available via API to select partners and enterprise customers.\",\n        tags: [\n            \"Anthropic\",\n            \"Claude\",\n            \"Constitutional AI\",\n            \"Safety\",\n            \"RLHF\"\n        ],\n        significance: \"major\",\n        provider: \"Anthropic\",\n        providerColor: \"#d97706\",\n        url: \"https://www.anthropic.com/news/introducing-claude\"\n    },\n    {\n        id: \"google-bard-launch\",\n        date: \"Mar 2023\",\n        dateNum: 202303,\n        title: \"Google Launches Bard — Search Giant Responds to ChatGPT\",\n        summary: \"Google launched Bard, a conversational AI built on its LaMDA language model, as a direct competitive response to ChatGPT's rapid growth. The launch was marred by a factual error in a promotional demo that contributed to Alphabet's stock dropping and erasing roughly $100 billion in market capitalization in a single day. Bard later transitioned to the Gemini brand and underlying Gemini models in February 2024.\",\n        tags: [\n            \"Google\",\n            \"Bard\",\n            \"LaMDA\",\n            \"Chatbot\",\n            \"Search\"\n        ],\n        significance: \"major\",\n        provider: \"Google\",\n        providerColor: \"#4285f4\",\n        url: \"https://blog.google/technology/ai/bard-google-ai-search-updates/\"\n    },\n    {\n        id: \"gpt-4-plugins\",\n        date: \"Mar 2023\",\n        dateNum: 202303,\n        title: \"ChatGPT Plugins — AI Gets Internet Access and Real-World Tools\",\n        summary: \"OpenAI introduced plugins for ChatGPT, allowing the model to browse the web in real time, execute code in a sandbox, and connect to third-party services such as Expedia, Klarna, and Wolfram Alpha. This was the first mainstream demonstration of LLMs operating as tool-using agents capable of taking real-world actions beyond generating text. The plugin architecture was the conceptual precursor to the later GPT Store and OpenAI Assistants API.\",\n        tags: [\n            \"OpenAI\",\n            \"ChatGPT\",\n            \"Plugins\",\n            \"Tool Use\",\n            \"Agents\",\n            \"Web Browsing\"\n        ],\n        significance: \"major\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://openai.com/index/chatgpt-plugins/\"\n    },\n    {\n        id: \"claude-2\",\n        date: \"Jul 2023\",\n        dateNum: 202307,\n        title: \"Claude 2 — 100K Token Context Window and Claude.ai Launch\",\n        summary: \"Anthropic released Claude 2, featuring a 100,000-token context window — roughly 75,000 words, or an entire novel — which far exceeded any competing model at the time. The model showed meaningful improvements over Claude 1 in coding, mathematics, and instruction following. Claude 2 was made available to the public via Claude.ai, moving Anthropic into the consumer market for the first time.\",\n        tags: [\n            \"Anthropic\",\n            \"Claude 2\",\n            \"Long Context\",\n            \"100K Tokens\",\n            \"Consumer AI\"\n        ],\n        significance: \"major\",\n        provider: \"Anthropic\",\n        providerColor: \"#d97706\",\n        url: \"https://www.anthropic.com/news/claude-2\"\n    },\n    {\n        id: \"llama-2-release\",\n        date: \"Jul 2023\",\n        dateNum: 202307,\n        title: \"LLaMA 2 Released — Meta Opens Frontier AI for Commercial Use\",\n        summary: \"Meta formally released LLaMA 2 in 7B, 13B, and 70B parameter sizes under a permissive license allowing free commercial use, in partnership with Microsoft. The 70B model was competitive with GPT-3.5 on many standard benchmarks. This release established LLaMA as the de facto foundation for the open-source AI ecosystem, with thousands of derivative fine-tunes, tools, and applications building on it within months.\",\n        tags: [\n            \"Meta\",\n            \"LLaMA 2\",\n            \"Open Source\",\n            \"Commercial License\",\n            \"Open Weights\"\n        ],\n        significance: \"landmark\",\n        provider: \"Meta\",\n        providerColor: \"#0866ff\",\n        url: \"https://ai.meta.com/blog/llama-2/\"\n    },\n    {\n        id: \"mistral-7b\",\n        date: \"Sep 2023\",\n        dateNum: 202309,\n        title: \"Mistral 7B — Efficient European Open-Weight Model\",\n        summary: \"French startup Mistral AI released Mistral 7B, a 7-billion-parameter model released with no license restrictions that outperformed LLaMA 2 13B across most benchmarks, demonstrating that efficient architecture choices could substantially narrow the gap with larger models. The model was distributed as a torrent and via direct download with no access controls. Mistral's team, drawn largely from DeepMind and Meta, subsequently raised $415 million at a roughly $2 billion valuation.\",\n        tags: [\n            \"Mistral AI\",\n            \"Open Weights\",\n            \"Efficiency\",\n            \"7B\",\n            \"Europe\"\n        ],\n        significance: \"notable\",\n        provider: \"Mistral AI\",\n        providerColor: \"#ff7000\",\n        url: \"https://mistral.ai/news/announcing-mistral-7b\"\n    },\n    {\n        id: \"gpt-4-vision\",\n        date: \"Sep 2023\",\n        dateNum: 202309,\n        title: \"GPT-4V Broadly Released — Vision and Voice Come to ChatGPT\",\n        summary: \"OpenAI broadly released GPT-4 with vision capabilities to ChatGPT Plus subscribers, enabling the model to analyze images, charts, photographs, and document scans and reason about their contents. Simultaneously, OpenAI launched voice mode featuring five distinct synthesized voices with natural conversational latency. These expansions marked the shift from text-only AI assistants toward genuinely multimodal consumer interfaces.\",\n        tags: [\n            \"OpenAI\",\n            \"GPT-4V\",\n            \"Vision\",\n            \"Multimodal\",\n            \"Voice\",\n            \"ChatGPT\"\n        ],\n        significance: \"major\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://openai.com/index/gpt-4v-system-card/\"\n    },\n    {\n        id: \"openai-custom-gpts\",\n        date: \"Nov 2023\",\n        dateNum: 202311,\n        title: \"OpenAI DevDay — Custom GPTs, GPT Store, and GPT-4 Turbo\",\n        summary: \"At its first developer conference, OpenAI announced custom GPTs — user-configurable AI assistants with custom instructions, knowledge files, and tool access — along with a GPT Store for sharing and discovering them. OpenAI also unveiled GPT-4 Turbo with a 128,000-token context window and significantly lower API pricing compared to the original GPT-4. The Assistants API with code execution and file retrieval was launched simultaneously.\",\n        tags: [\n            \"OpenAI\",\n            \"GPT Store\",\n            \"Custom GPTs\",\n            \"GPT-4 Turbo\",\n            \"128K Context\",\n            \"API\"\n        ],\n        significance: \"major\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://openai.com/index/introducing-gpts/\"\n    },\n    {\n        id: \"sam-altman-fired\",\n        date: \"Nov 2023\",\n        dateNum: 202311,\n        title: \"OpenAI Board Fires and Reinstates Sam Altman in Five Days\",\n        summary: \"OpenAI's board abruptly terminated CEO Sam Altman on November 17, citing a loss of confidence in his candor with the board. The decision triggered a company-wide revolt: nearly all 770 OpenAI employees signed a letter threatening to resign unless Altman was reinstated. Altman returned as CEO five days later with a substantially restructured board, and the episode prompted ongoing discussion about AI governance and the tension between OpenAI's nonprofit mission and its commercial scale.\",\n        tags: [\n            \"OpenAI\",\n            \"Governance\",\n            \"Sam Altman\",\n            \"Corporate\",\n            \"Safety Mission\"\n        ],\n        significance: \"notable\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://openai.com/index/openai-response/\"\n    },\n    {\n        id: \"gemini-1-announce\",\n        date: \"Dec 2023\",\n        dateNum: 202312,\n        title: \"Google Announces Gemini 1.0 — Natively Multimodal Model Family\",\n        summary: \"Google announced the Gemini 1.0 model family in three sizes — Ultra, Pro, and Nano — built to be natively multimodal from the ground up, understanding and generating across text, images, audio, and video in a single unified model. Gemini Ultra reportedly surpassed GPT-4 on 30 of 32 benchmarks evaluated, including the MMLU academic knowledge test. Gemini Nano was designed to run on-device on Pixel 8 Pro smartphones without a network connection.\",\n        tags: [\n            \"Google\",\n            \"Gemini\",\n            \"Multimodal\",\n            \"Benchmark\",\n            \"On-Device\",\n            \"MMLU\"\n        ],\n        significance: \"landmark\",\n        provider: \"Google\",\n        providerColor: \"#4285f4\",\n        url: \"https://blog.google/technology/ai/google-gemini-ai/\"\n    },\n    // ── 2024 ─────────────────────────────────────────────────────────────────\n    {\n        id: \"sora-announcement\",\n        date: \"Feb 2024\",\n        dateNum: 202402,\n        title: \"OpenAI Sora — Cinematic Text-to-Video AI Announced\",\n        summary: \"OpenAI unveiled Sora, a text-to-video model capable of generating up to 60-second photorealistic videos with consistent physics, camera movement, and object permanence across frames. Demo videos showing hyper-realistic cityscapes, animals in motion, and abstract scenes went viral immediately. OpenAI described Sora as 'a world simulator' and stated it was not yet available to the public, instead sharing access with red teamers and visual artists.\",\n        tags: [\n            \"OpenAI\",\n            \"Sora\",\n            \"Text-to-Video\",\n            \"Video Generation\",\n            \"World Simulator\"\n        ],\n        significance: \"landmark\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://openai.com/index/sora/\"\n    },\n    {\n        id: \"gemini-1-5\",\n        date: \"Feb 2024\",\n        dateNum: 202402,\n        title: \"Gemini 1.5 Pro — One Million Token Context Window\",\n        summary: \"Google announced Gemini 1.5 Pro featuring a one-million-token context window — enough to process approximately one hour of video, 11 hours of audio, 30,000 lines of code, or 700,000 words in a single prompt. This was a ten-fold increase over the previous largest context window among major models. Google attributed the capability to a Mixture of Experts architecture, which also made the model more computationally efficient than Gemini 1.0 Ultra.\",\n        tags: [\n            \"Google\",\n            \"Gemini 1.5\",\n            \"1M Context\",\n            \"Mixture of Experts\",\n            \"Long Context\"\n        ],\n        significance: \"landmark\",\n        provider: \"Google\",\n        providerColor: \"#4285f4\",\n        url: \"https://blog.google/technology/ai/google-gemini-next-generation-model-february-2024/\"\n    },\n    {\n        id: \"claude-3-family\",\n        date: \"Mar 2024\",\n        dateNum: 202403,\n        title: \"Claude 3 Family — Haiku, Sonnet, and Opus Set New Benchmarks\",\n        summary: \"Anthropic launched the Claude 3 model family in three tiers — Haiku, Sonnet, and Opus — covering fast and cheap to most capable. Claude 3 Opus surpassed GPT-4 on most major benchmarks at launch, including MMLU, HumanEval coding, and GPQA graduate-level science, marking the first time a non-OpenAI model led broad academic evaluations across the board. All three Claude 3 models featured a 200,000-token context window as standard.\",\n        tags: [\n            \"Anthropic\",\n            \"Claude 3\",\n            \"Opus\",\n            \"Sonnet\",\n            \"Haiku\",\n            \"200K Context\",\n            \"Benchmark\"\n        ],\n        significance: \"landmark\",\n        provider: \"Anthropic\",\n        providerColor: \"#d97706\",\n        url: \"https://www.anthropic.com/news/claude-3-family\"\n    },\n    {\n        id: \"llama-3-release\",\n        date: \"Apr 2024\",\n        dateNum: 202404,\n        title: \"LLaMA 3 — Meta Distributes AI to Billions via Social Platforms\",\n        summary: \"Meta released LLaMA 3 in 8B and 70B parameter sizes, with the 70B model matching or exceeding GPT-3.5 Turbo on most benchmarks while remaining fully open for download. Simultaneously, Meta launched Meta AI, a consumer assistant powered by LLaMA 3, integrated natively into WhatsApp, Instagram, Messenger, and Facebook search — making a frontier-class model available to billions of users without requiring any separate sign-up.\",\n        tags: [\n            \"Meta\",\n            \"LLaMA 3\",\n            \"Open Weights\",\n            \"Meta AI\",\n            \"Consumer AI\",\n            \"Social\"\n        ],\n        significance: \"major\",\n        provider: \"Meta\",\n        providerColor: \"#0866ff\",\n        url: \"https://ai.meta.com/blog/meta-llama-3/\"\n    },\n    {\n        id: \"gpt-4o\",\n        date: \"May 2024\",\n        dateNum: 202405,\n        title: \"GPT-4o — Omni Model With Real-Time Audio and Vision\",\n        summary: \"OpenAI launched GPT-4o ('omni'), a unified model that natively processes text, audio, and images in a single neural network rather than through a pipeline of separate specialist models. GPT-4o could respond to audio in as little as 232 milliseconds — matching human conversational latency — and detect emotional tone in speech. The model was made available to all free ChatGPT users, removing the paid-only barrier for GPT-4-class capabilities for the first time.\",\n        tags: [\n            \"OpenAI\",\n            \"GPT-4o\",\n            \"Omni\",\n            \"Real-Time Audio\",\n            \"Multimodal\",\n            \"Free Access\"\n        ],\n        significance: \"landmark\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://openai.com/index/hello-gpt-4o/\"\n    },\n    {\n        id: \"claude-3-5-sonnet\",\n        date: \"Jun 2024\",\n        dateNum: 202406,\n        title: \"Claude 3.5 Sonnet — New State of the Art at Mid-Tier Cost\",\n        summary: \"Anthropic released Claude 3.5 Sonnet, which outperformed Claude 3 Opus across most benchmarks while running at Sonnet-tier speed and pricing — a significant efficiency gain. It achieved 49% on the SWE-bench Verified coding evaluation, surpassing all other models at the time. Anthropic simultaneously introduced Artifacts, an interactive canvas panel within Claude.ai for viewing, editing, and running generated code and documents in real time.\",\n        tags: [\n            \"Anthropic\",\n            \"Claude 3.5 Sonnet\",\n            \"Coding\",\n            \"SWE-bench\",\n            \"Artifacts\",\n            \"Efficiency\"\n        ],\n        significance: \"landmark\",\n        provider: \"Anthropic\",\n        providerColor: \"#d97706\",\n        url: \"https://www.anthropic.com/news/claude-3-5-sonnet\"\n    },\n    {\n        id: \"apple-intelligence\",\n        date: \"Jun 2024\",\n        dateNum: 202406,\n        title: \"Apple Intelligence — On-Device AI for iPhone, iPad, and Mac\",\n        summary: \"Apple announced Apple Intelligence at WWDC 2024, a suite of AI features built into iOS 18, iPadOS 18, and macOS Sequoia. Capabilities included AI writing tools, an image generation system called Image Playground, an enhanced context-aware Siri, and a Private Cloud Compute architecture designed to process sensitive requests on Apple silicon servers without logging user data. Apple also announced an opt-in ChatGPT integration for queries Siri cannot answer locally.\",\n        tags: [\n            \"Apple\",\n            \"Apple Intelligence\",\n            \"On-Device AI\",\n            \"Privacy\",\n            \"Siri\",\n            \"iOS 18\"\n        ],\n        significance: \"major\",\n        provider: \"Apple\",\n        providerColor: \"#555555\",\n        url: \"https://www.apple.com/newsroom/2024/06/introducing-apple-intelligence-for-iphone-ipad-and-mac/\"\n    },\n    {\n        id: \"openai-o1\",\n        date: \"Sep 2024\",\n        dateNum: 202409,\n        title: \"OpenAI o1 — Reasoning Models That Think Before Answering\",\n        summary: \"OpenAI released o1, a reasoning model that spends additional compute on internal chain-of-thought 'thinking' steps before producing its final answer, trading latency for accuracy on complex tasks. o1 scored 83% on International Olympiad in Informatics competition problems and performed at PhD level on the GPQA science benchmark covering biology, chemistry, and physics. It introduced inference-time compute scaling as a distinct axis from model size for improving AI capability.\",\n        tags: [\n            \"OpenAI\",\n            \"o1\",\n            \"Reasoning\",\n            \"Chain-of-Thought\",\n            \"Inference Compute\",\n            \"GPQA\"\n        ],\n        significance: \"landmark\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://openai.com/index/introducing-openai-o1-preview/\"\n    },\n    {\n        id: \"anthropic-computer-use\",\n        date: \"Oct 2024\",\n        dateNum: 202410,\n        title: \"Anthropic Computer Use — Claude Controls Desktops Autonomously\",\n        summary: \"Anthropic released a Computer Use capability for Claude 3.5 Sonnet in public beta, enabling the model to view screenshots and operate computers by moving a cursor, clicking interface elements, and typing text — without requiring custom API integrations for each application. This represented a significant step toward general-purpose computer agents that could automate any software task a human can perform on a screen. Anthropic flagged the capability as experimental and susceptible to prompt injection.\",\n        tags: [\n            \"Anthropic\",\n            \"Claude\",\n            \"Computer Use\",\n            \"Agents\",\n            \"Automation\",\n            \"Desktop\"\n        ],\n        significance: \"major\",\n        provider: \"Anthropic\",\n        providerColor: \"#d97706\",\n        url: \"https://www.anthropic.com/news/computer-use\"\n    },\n    {\n        id: \"alphafold-nobel\",\n        date: \"Oct 2024\",\n        dateNum: 202410,\n        title: \"Nobel Prize in Chemistry Awarded for AlphaFold\",\n        summary: \"The Nobel Committee awarded the 2024 Nobel Prize in Chemistry to Demis Hassabis and John Jumper of Google DeepMind for AlphaFold, and to David Baker of the University of Washington for computational protein design. AlphaFold had predicted the three-dimensional structures of over 200 million proteins spanning virtually every known organism, solving a 50-year grand challenge in structural biology. The Nobel Committee also awarded the 2024 Physics Nobel to Geoffrey Hinton and John Hopfield for foundational work on neural networks — two Nobel Prizes for AI research in a single year.\",\n        tags: [\n            \"DeepMind\",\n            \"AlphaFold\",\n            \"Nobel Prize\",\n            \"Protein Folding\",\n            \"Biology\",\n            \"Geoffrey Hinton\"\n        ],\n        significance: \"landmark\",\n        provider: \"DeepMind\",\n        providerColor: \"#4285f4\",\n        url: \"https://www.nobelprize.org/prizes/chemistry/2024/press-release/\"\n    },\n    {\n        id: \"gemini-2-flash\",\n        date: \"Dec 2024\",\n        dateNum: 202412,\n        title: \"Gemini 2.0 Flash — Google Launches Agentic Model Generation\",\n        summary: \"Google released Gemini 2.0 Flash as the first model in its Gemini 2.0 family, designed for agentic use cases with native multimodal inputs, real-time audio output, and native image generation capability. The model featured improved tool use and was optimized for high-frequency tasks requiring low latency at minimal cost. Google framed the Gemini 2.0 generation as the beginning of what it called the 'agentic era' of AI development.\",\n        tags: [\n            \"Google\",\n            \"Gemini 2.0\",\n            \"Flash\",\n            \"Agents\",\n            \"Multimodal\",\n            \"Image Generation\"\n        ],\n        significance: \"major\",\n        provider: \"Google\",\n        providerColor: \"#4285f4\",\n        url: \"https://blog.google/technology/google-deepmind/google-gemini-ai-update-december-2024/\"\n    },\n    {\n        id: \"sora-public-release\",\n        date: \"Dec 2024\",\n        dateNum: 202412,\n        title: \"Sora Publicly Released — Text-to-Video Available to Subscribers\",\n        summary: \"OpenAI made Sora available to ChatGPT Plus and Pro subscribers after approximately ten months of preview access limited to selected creators and red teamers. The public version generated videos up to 20 seconds in length at 1080p resolution, with a watermarking system to identify AI-generated content. The release was part of OpenAI's '12 Days of OpenAI' announcement series in December 2024.\",\n        tags: [\n            \"OpenAI\",\n            \"Sora\",\n            \"Text-to-Video\",\n            \"Video Generation\",\n            \"Consumer\"\n        ],\n        significance: \"major\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://openai.com/index/sora-is-here/\"\n    },\n    // ── 2025 ─────────────────────────────────────────────────────────────────\n    {\n        id: \"deepseek-r1\",\n        date: \"Jan 2025\",\n        dateNum: 202501,\n        title: \"DeepSeek R1 — Efficient Reasoning Model Shocks the Industry\",\n        summary: \"DeepSeek released R1, a reasoning model built in China that matched OpenAI o1's performance on major benchmarks while being trained at a fraction of the cost and under US semiconductor export restrictions using older NVIDIA hardware. The model was released fully open-source under an MIT license. NVIDIA lost approximately $600 billion in market capitalization in a single trading day as investors questioned whether the most expensive AI infrastructure was necessary to achieve frontier performance.\",\n        tags: [\n            \"DeepSeek\",\n            \"R1\",\n            \"Reasoning\",\n            \"Open Source\",\n            \"Efficiency\",\n            \"China\"\n        ],\n        significance: \"landmark\",\n        provider: \"DeepSeek\",\n        providerColor: \"#1a73e8\",\n        url: \"https://github.com/deepseek-ai/DeepSeek-R1\"\n    },\n    {\n        id: \"openai-operator\",\n        date: \"Jan 2025\",\n        dateNum: 202501,\n        title: \"OpenAI Operator — AI Agent That Browses and Acts on the Web\",\n        summary: \"OpenAI launched Operator, a standalone AI agent capable of navigating websites, filling in forms, completing checkouts, and booking reservations autonomously using a standard web browser. It used a Computer-Using Agent model trained specifically on graphical user interface interaction rather than relying on structured APIs. Operator launched for ChatGPT Pro subscribers in the United States, representing OpenAI's first dedicated agentic product separate from ChatGPT.\",\n        tags: [\n            \"OpenAI\",\n            \"Operator\",\n            \"Agents\",\n            \"Browser Automation\",\n            \"Web\",\n            \"Agentic\"\n        ],\n        significance: \"major\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://openai.com/index/introducing-operator/\"\n    },\n    {\n        id: \"claude-3-7-sonnet\",\n        date: \"Feb 2025\",\n        dateNum: 202502,\n        title: \"Claude 3.7 Sonnet and Claude Code — Extended Thinking and Agentic Coding\",\n        summary: \"Anthropic released Claude 3.7 Sonnet, the first model to offer both a standard fast response mode and an optional Extended Thinking mode that surfaces the model's chain-of-thought reasoning to users before producing a final answer. It set a new record of 62.3% on SWE-bench Verified, the leading coding agent benchmark. Anthropic simultaneously launched Claude Code, a terminal-based agentic coding tool that could autonomously write, edit, test, and debug entire codebases.\",\n        tags: [\n            \"Anthropic\",\n            \"Claude 3.7\",\n            \"Extended Thinking\",\n            \"Claude Code\",\n            \"SWE-bench\",\n            \"Agentic\"\n        ],\n        significance: \"landmark\",\n        provider: \"Anthropic\",\n        providerColor: \"#d97706\",\n        url: \"https://www.anthropic.com/news/claude-3-7-sonnet\"\n    },\n    {\n        id: \"gemini-2-5-pro\",\n        date: \"Mar 2025\",\n        dateNum: 202503,\n        title: \"Gemini 2.5 Pro — Google's Thinking Model Tops Coding Leaderboards\",\n        summary: \"Google released Gemini 2.5 Pro Experimental, a thinking model that immediately ranked first on the LMArena (formerly LMSys) leaderboard and set new records on the WebDev Arena benchmark for generating web applications. It was widely praised for producing complex, functional interactive web apps from natural language descriptions with high accuracy. The model supported a one-million-token context window and offered competitive API pricing relative to OpenAI's reasoning models.\",\n        tags: [\n            \"Google\",\n            \"Gemini 2.5 Pro\",\n            \"Reasoning\",\n            \"Coding\",\n            \"LMArena\",\n            \"Thinking\"\n        ],\n        significance: \"major\",\n        provider: \"Google\",\n        providerColor: \"#4285f4\",\n        url: \"https://blog.google/technology/google-deepmind/gemini-model-thinking-updates-march-2025/\"\n    },\n    {\n        id: \"gpt-4o-image-gen\",\n        date: \"Mar 2025\",\n        dateNum: 202503,\n        title: \"GPT-4o Native Image Generation Goes Viral\",\n        summary: \"OpenAI launched native image generation within GPT-4o, replacing its previous DALL-E 3 integration with a system capable of producing significantly more photorealistic images with accurate text rendering — a longstanding weakness of diffusion models. The feature generated widespread attention when users discovered it could replicate the visual style of Studio Ghibli animated films. ChatGPT reached 150 million daily active users in the week following launch, a new record for the platform.\",\n        tags: [\n            \"OpenAI\",\n            \"GPT-4o\",\n            \"Image Generation\",\n            \"Multimodal\",\n            \"ChatGPT\",\n            \"Creative\"\n        ],\n        significance: \"major\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://openai.com/index/introducing-4o-image-generation/\"\n    },\n    {\n        id: \"openai-o3\",\n        date: \"Apr 2025\",\n        dateNum: 202504,\n        title: \"OpenAI o3 and o4-mini — Agentic Reasoning With Integrated Tool Use\",\n        summary: \"OpenAI released o3 and o4-mini, reasoning models that can invoke tools — including web search, Python code execution, and image analysis — directly within their chain-of-thought thinking process rather than as a separate outer loop. o3 scored 69.1% on SWE-bench Verified and set new records on ARC-AGI-1, a benchmark designed to measure reasoning beyond pattern matching. The models represented the first integration of native tool use into the reasoning loop itself.\",\n        tags: [\n            \"OpenAI\",\n            \"o3\",\n            \"o4-mini\",\n            \"Reasoning\",\n            \"Tool Use\",\n            \"ARC-AGI\",\n            \"Agentic\"\n        ],\n        significance: \"landmark\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://openai.com/index/introducing-o3-and-o4-mini/\"\n    },\n    {\n        id: \"llama-4-release\",\n        date: \"Apr 2025\",\n        dateNum: 202504,\n        title: \"LLaMA 4 — Meta's Mixture-of-Experts Open Frontier Models\",\n        summary: \"Meta released the LLaMA 4 model family including Scout, a 17-billion-active-parameter model supporting a 10-million-token context window — the largest of any publicly released model at the time — and Maverick, a Mixture of Experts model competitive with GPT-4o and Gemini 2.0 Flash on most standard benchmarks. A larger model called Behemoth was announced as still in training. All LLaMA 4 models were released under Meta's custom open license permitting broad commercial use.\",\n        tags: [\n            \"Meta\",\n            \"LLaMA 4\",\n            \"Mixture of Experts\",\n            \"10M Context\",\n            \"Open Weights\",\n            \"MoE\"\n        ],\n        significance: \"major\",\n        provider: \"Meta\",\n        providerColor: \"#0866ff\",\n        url: \"https://ai.meta.com/blog/llama-4-multimodal-intelligence/\"\n    },\n    {\n        id: \"claude-4-sonnet-opus\",\n        date: \"May 2025\",\n        dateNum: 202505,\n        title: \"Claude Sonnet 4 and Opus 4 — Anthropic's Most Capable Generation\",\n        summary: \"Anthropic released Claude Sonnet 4 and Claude Opus 4, with Sonnet 4 achieving 72.7% on SWE-bench Verified — a new record at launch — and Opus 4 positioned as the highest-capability option for the most demanding tasks. Both models featured improved instruction following, significantly reduced unnecessary refusals compared to earlier versions, and enhanced agentic capabilities for multi-step workflows. Claude Sonnet 4 became the primary model powering Cursor's AI coding assistant.\",\n        tags: [\n            \"Anthropic\",\n            \"Claude 4\",\n            \"Opus 4\",\n            \"Sonnet 4\",\n            \"SWE-bench\",\n            \"Coding\",\n            \"Agents\"\n        ],\n        significance: \"landmark\",\n        provider: \"Anthropic\",\n        providerColor: \"#d97706\",\n        url: \"https://www.anthropic.com/news/claude-4\"\n    },\n    // ── 2025 (continued) ─────────────────────────────────────────────────────\n    {\n        id: \"meta-scale-ai\",\n        date: \"Jun 2025\",\n        dateNum: 202506,\n        title: \"Meta Acquires 49% of Scale AI — $29 Billion Data Valuation\",\n        summary: \"Meta acquired a 49% non-voting stake in Scale AI, valuing the data-labeling and AI evaluation company at $29 billion — the largest acquisition in AI infrastructure at the time. The deal gave Meta privileged access to Scale's training data pipelines and human-feedback systems, directly competing with OpenAI and Anthropic on the data layer. Meta simultaneously announced Scale AI's CEO Alexandr Wang would join Meta's board, signaling a deeper strategic alignment.\",\n        tags: [\n            \"Meta\",\n            \"Scale AI\",\n            \"Data\",\n            \"Infrastructure\",\n            \"Acquisition\"\n        ],\n        significance: \"major\",\n        provider: \"Meta\",\n        providerColor: \"#0866ff\"\n    },\n    {\n        id: \"gpt-5-launch\",\n        date: \"Aug 2025\",\n        dateNum: 202508,\n        title: \"GPT-5 Launches — Unified Reasoning Model Free for Everyone\",\n        summary: \"OpenAI released GPT-5 on August 7, 2025 as its first model unifying fast chat and deep reasoning in a single endpoint, ending the need to choose between GPT-4o and the o-series. GPT-5 scored 74.9% on SWE-bench Verified, 94.6% on AIME 2025 without tools, and 84.2% on MMMU, setting new records across coding, mathematics, and multimodal understanding simultaneously. The model was made available to all free ChatGPT users at launch — the first time a unified reasoning model reached the free tier.\",\n        tags: [\n            \"OpenAI\",\n            \"GPT-5\",\n            \"Reasoning\",\n            \"SWE-bench\",\n            \"Free Access\",\n            \"Multimodal\"\n        ],\n        significance: \"landmark\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://openai.com/index/introducing-gpt-5/\"\n    },\n    {\n        id: \"gemini-3-pro\",\n        date: \"Nov 2025\",\n        dateNum: 202511,\n        title: \"Gemini 3 Pro — Google's Most Capable Multimodal Model Launches\",\n        summary: \"Google launched Gemini 3 Pro on November 20, 2025 across Search, the Gemini app, AI Studio, and Vertex AI simultaneously. The model features a 1,048,576-token context window, native understanding of text, images, video, audio, and PDFs, and a Deep Think mode for demanding reasoning tasks. Gemini 3 Pro was immediately deployed as the backbone of Google's consumer AI products, replacing Gemini 2.0, and marked Google's most aggressive model launch across its entire product surface at once.\",\n        tags: [\n            \"Google\",\n            \"Gemini 3\",\n            \"Multimodal\",\n            \"1M Context\",\n            \"Deep Think\",\n            \"Agents\"\n        ],\n        significance: \"landmark\",\n        provider: \"Google\",\n        providerColor: \"#4285f4\",\n        url: \"https://workspaceupdates.googleblog.com/2025/11/introducing-gemini-3-pro-for-gemini-app.html\"\n    },\n    {\n        id: \"claude-opus-4-5\",\n        date: \"Nov 2025\",\n        dateNum: 202511,\n        title: \"Claude Opus 4.5 — First Model to Break 80% on SWE-bench\",\n        summary: \"Anthropic released Claude Opus 4.5 on November 24, 2025, scoring 80.9% on SWE-bench Verified — the first AI model to cross the 80% threshold on the leading real-world coding benchmark, surpassing GPT-5.1 at 76.3% and Gemini 3 Pro at 76.2%. Pricing dropped by approximately 67% from previous Opus models to $5 per million input tokens and $25 per million output tokens. An 'endless chat' feature automatically compressed context at limits, enabling uninterrupted multi-hour agentic workflows.\",\n        tags: [\n            \"Anthropic\",\n            \"Claude Opus 4.5\",\n            \"SWE-bench\",\n            \"Coding\",\n            \"Agents\",\n            \"Pricing\"\n        ],\n        significance: \"landmark\",\n        provider: \"Anthropic\",\n        providerColor: \"#d97706\",\n        url: \"https://www.anthropic.com/news/claude-opus-4-5\"\n    },\n    {\n        id: \"gpt-5-2-codex\",\n        date: \"Dec 2025\",\n        dateNum: 202512,\n        title: \"OpenAI GPT-5.2-Codex — Agentic Coding Specialist Counters Gemini 3\",\n        summary: \"OpenAI released GPT-5.2-Codex in December 2025 as a specialist coding model optimized for multi-step agentic software engineering tasks, directly responding to Gemini 3 Pro's strong coding performance. The model was positioned for autonomous repository-level coding, integration testing, and codebase exploration rather than single-file tasks. GPT-5.2-Codex debuted on the OpenAI Codex platform and via the Assistants API, targeting professional engineering teams running long-horizon automated workflows.\",\n        tags: [\n            \"OpenAI\",\n            \"GPT-5.2\",\n            \"Codex\",\n            \"Coding\",\n            \"Agents\",\n            \"Agentic\"\n        ],\n        significance: \"major\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://openai.com/index/introducing-gpt-5-2-codex/\"\n    },\n    {\n        id: \"meta-manus\",\n        date: \"Dec 2025\",\n        dateNum: 202512,\n        title: \"Meta Acquires Manus AI for $2B+ — General-Purpose Agent Platform\",\n        summary: \"Meta acquired Manus, a Singapore-based AI startup, for over $2 billion — the largest acquisition of an AI agent company to date. Manus had built a general-purpose AI agent capable of performing complex multi-step real-world tasks across web browsing, file management, coding, and data analysis without domain-specific customization. The acquisition positioned Meta to compete directly with OpenAI Operator and Anthropic Computer Use in the emerging market for autonomous agent products.\",\n        tags: [\n            \"Meta\",\n            \"Manus\",\n            \"Agents\",\n            \"Acquisition\",\n            \"Automation\"\n        ],\n        significance: \"major\",\n        provider: \"Meta\",\n        providerColor: \"#0866ff\"\n    },\n    // ── 2026 ─────────────────────────────────────────────────────────────────\n    {\n        id: \"gemini-3-1-pro\",\n        date: \"Feb 2026\",\n        dateNum: 202602,\n        title: \"Gemini 3.1 Pro — Leads Every Published Reasoning Benchmark\",\n        summary: \"Google released Gemini 3.1 Pro in February 2026, immediately reaching the top of all major published benchmarks including GPQA Diamond at 94.3% and ARC-AGI-2 at 77.1%. The model matched GPT-5.5's 1-million-token context window while offering more competitive API pricing, making it the preferred choice for cost-sensitive high-throughput workloads. Gemini 3.1 Flash-Lite launched simultaneously as Google's most cost-efficient model for latency-critical production deployments.\",\n        tags: [\n            \"Google\",\n            \"Gemini 3.1 Pro\",\n            \"Reasoning\",\n            \"GPQA\",\n            \"ARC-AGI\",\n            \"Benchmark\"\n        ],\n        significance: \"major\",\n        provider: \"Google\",\n        providerColor: \"#4285f4\"\n    },\n    {\n        id: \"openai-122b-funding\",\n        date: \"Mar 2026\",\n        dateNum: 202603,\n        dateDay: 31,\n        title: \"OpenAI Closes $122B Round at $852B Valuation — Largest Private Raise Ever\",\n        summary: \"OpenAI closed a $122 billion funding round on March 31, 2026 at an $852 billion post-money valuation — the largest private capital raise in history. Amazon committed $50 billion, SoftBank and Nvidia each contributed $30 billion, with Andreessen Horowitz and D.E. Shaw also participating. The round included $3 billion from individual investors via bank channels, and is expected to fund global AI infrastructure buildout and an anticipated IPO.\",\n        tags: [\n            \"OpenAI\",\n            \"Funding\",\n            \"Valuation\",\n            \"SoftBank\",\n            \"Amazon\",\n            \"IPO\"\n        ],\n        significance: \"major\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://openai.com/index/accelerating-the-next-phase-ai/\"\n    },\n    {\n        id: \"claude-mythos-glasswing\",\n        date: \"Apr 2026\",\n        dateNum: 202604,\n        title: \"Claude Mythos and Project Glasswing — AI Discovers Thousands of Zero-Days\",\n        summary: \"Anthropic announced Claude Mythos Preview, a frontier model sitting a full capability tier above Opus 4.7 and not available to the public, alongside Project Glasswing — an initiative to use Mythos to secure critical software infrastructure. Using Mythos, Anthropic autonomously identified thousands of zero-day vulnerabilities across every major operating system and web browser, including a 17-year-old remote code execution vulnerability in FreeBSD that allows complete server takeover. Launch partners include AWS, Apple, Cisco, CrowdStrike, Google, JPMorganChase, Microsoft, and NVIDIA, with $100 million in model credits committed.\",\n        tags: [\n            \"Anthropic\",\n            \"Claude Mythos\",\n            \"Project Glasswing\",\n            \"Security\",\n            \"Zero-Day\",\n            \"Cybersecurity\"\n        ],\n        significance: \"landmark\",\n        provider: \"Anthropic\",\n        providerColor: \"#d97706\",\n        url: \"https://www.anthropic.com/glasswing\"\n    },\n    {\n        id: \"gemini-3-1-ultra\",\n        date: \"Apr 2026\",\n        dateNum: 202604,\n        title: \"Gemini 3.1 Ultra — 2M-Token Context Window, Full Native Multimodal\",\n        summary: \"Google released Gemini 3.1 Ultra in April 2026 with the largest context window of any publicly available model at 2 million tokens — double the 1M-token limit of Gemini 3.1 Pro. The model reasons natively across text, image, audio, and video in a single pass without separate pipelines, enabling tasks like auditing a full year of all-hands recordings alongside a complete legal discovery set in one prompt. Gemini 3.1 Ultra surpassed GPT-5.5 on the MMLU-Pro and GPQA Diamond benchmarks, making it Google's most capable model available via the Vertex AI API at launch.\",\n        tags: [\n            \"Google\",\n            \"Gemini 3.1 Ultra\",\n            \"2M Context\",\n            \"Multimodal\",\n            \"Benchmark\",\n            \"Vertex AI\"\n        ],\n        significance: \"major\",\n        provider: \"Google\",\n        providerColor: \"#4285f4\",\n        url: \"https://medium.com/@WinTK-Bangladesh/gemini-3-1-ultra-is-here-2-million-token-context-full-multimodal-zero-compromise-ca3f2a8d1254\"\n    },\n    {\n        id: \"claude-opus-4-7\",\n        date: \"Apr 2026\",\n        dateNum: 202604,\n        title: \"Claude Opus 4.7 — Anthropic's 2026 Flagship With Enhanced Vision and Coding\",\n        summary: \"Anthropic released Claude Opus 4.7 on April 16, 2026, delivering a 10.9-point improvement on SWE-bench Pro to 64.3%, a threefold increase in visual resolution to 3.75 megapixels per image, enhanced file-system memory for persistent agentic tasks, and a new 'xhigh' reasoning effort level above the previous maximum. Pricing remained unchanged at $5 per million input and $25 per million output tokens despite the capability improvements. Opus 4.7 led software engineering and tool orchestration benchmarks against all competing models at launch.\",\n        tags: [\n            \"Anthropic\",\n            \"Claude Opus 4.7\",\n            \"SWE-bench\",\n            \"Vision\",\n            \"Coding\",\n            \"Reasoning\"\n        ],\n        significance: \"major\",\n        provider: \"Anthropic\",\n        providerColor: \"#d97706\",\n        url: \"https://www.anthropic.com/news/claude-opus-4-7\"\n    },\n    {\n        id: \"gpt-5-5\",\n        date: \"Apr 2026\",\n        dateNum: 202604,\n        title: \"GPT-5.5 — OpenAI's 1M-Context Default Model With Agentic Workflows\",\n        summary: \"OpenAI released GPT-5.5 on April 24, 2026, matching Gemini 3.1 Pro's 1-million-token context window for the first time while improving token efficiency at equivalent latency versus GPT-5.4. Greg Brockman described GPT-5.5 as 'a new class of intelligence' for its ability to decompose ambiguous problems and determine next steps without explicit instruction. GPT-5.5 Instant subsequently became the default model for all ChatGPT users in May 2026, replacing GPT-4o as the standard-tier model.\",\n        tags: [\n            \"OpenAI\",\n            \"GPT-5.5\",\n            \"1M Context\",\n            \"Agentic\",\n            \"ChatGPT\",\n            \"Default Model\"\n        ],\n        significance: \"major\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://techcrunch.com/2026/05/05/openai-releases-gpt-5-5-instant-a-new-default-model-for-chatgpt/\"\n    },\n    {\n        id: \"anthropic-30b-revenue\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 8,\n        title: \"Anthropic Hits $30B Revenue Run-Rate — $950B Valuation Talks\",\n        summary: \"Anthropic's annualized revenue surpassed $30 billion in May 2026 — more than triple its $9 billion run-rate at end of 2025 — driven by explosive enterprise adoption of Claude Opus 4.7 and Claude Code. The company entered talks to raise $30–50 billion at a valuation approaching $950 billion, which would make it one of the most valuable private companies in history. Anthropic simultaneously expanded its compute partnership with Google and Broadcom to support the infrastructure demands of serving its rapidly growing customer base.\",\n        tags: [\n            \"Anthropic\",\n            \"Revenue\",\n            \"Valuation\",\n            \"Enterprise\",\n            \"Growth\"\n        ],\n        significance: \"notable\",\n        provider: \"Anthropic\",\n        providerColor: \"#d97706\"\n    },\n    {\n        id: \"xai-dissolved-anthropic-compute\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 6,\n        title: \"xAI Dissolved — SpaceX Hands Colossus 1 Compute to Anthropic\",\n        summary: \"Elon Musk announced on May 6, 2026 that xAI would be dissolved as an independent company and rebranded SpaceXAI, citing Anthropic's rapid growth and safety focus as factors in his change of view. Anthropic simultaneously signed a compute agreement with SpaceX giving it exclusive access to the Colossus 1 facility in Memphis — over 220,000 NVIDIA H100/H200/GB200 GPUs and 300 megawatts of capacity — driven by an 80-fold revenue surge in a single quarter that overwhelmed Anthropic's existing infrastructure. Anthropic also expressed interest in extending the partnership to gigawatt-scale orbital compute with SpaceX.\",\n        tags: [\n            \"Anthropic\",\n            \"xAI\",\n            \"SpaceX\",\n            \"Compute\",\n            \"Colossus\",\n            \"Elon Musk\",\n            \"Infrastructure\"\n        ],\n        significance: \"major\",\n        provider: \"Anthropic\",\n        providerColor: \"#d97706\",\n        url: \"https://x.ai/news/anthropic-compute-partnership\"\n    },\n    // ── Auto-updated 2026-05-18 ────────────────────────────────────────────\n    {\n        id: \"mistral-medium-3-5\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 1,\n        title: \"Mistral Medium 3.5 — 128B Open-Weight Model With 77.6% SWE-bench\",\n        summary: \"Mistral AI released Medium 3.5, a 128-billion-parameter dense model with a 256,000-token context window, scoring 77.6% on SWE-bench Verified and unifying instruction-following, reasoning, coding, and vision in a single set of weights. The model was released with open weights under a modified MIT license and priced at $1.50/$7.50 per million input/output tokens via API. Mistral simultaneously launched Work Mode in Le Chat — an agentic interface powered by Medium 3.5 that executes multi-step workflows across connected tools in parallel.\",\n        tags: [\n            \"Mistral AI\",\n            \"Medium 3.5\",\n            \"128B\",\n            \"Open Weights\",\n            \"SWE-bench\",\n            \"Agents\"\n        ],\n        significance: \"major\",\n        provider: \"Mistral AI\",\n        providerColor: \"#ff7000\",\n        url: \"https://mistral.ai/news/vibe-remote-agents-mistral-medium-3-5\"\n    },\n    {\n        id: \"microsoft-agent-365-ga\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 1,\n        title: \"Microsoft Agent 365 Generally Available — Enterprise AI Agent Governance\",\n        summary: \"Microsoft made Agent 365 generally available on May 1, 2026, introducing enterprise-grade visibility, governance, and security controls for AI agent fleets at $15 per user per month. The platform extends Microsoft Entra network controls to Copilot Studio agents and locally-running agents, enabling IT teams to identify unsanctioned AI usage, restrict connections to approved destinations, and block prompt-injection attacks. Agent 365 is bundled into the new Microsoft 365 E7 tier alongside Copilot and the full Microsoft 365 E5 suite.\",\n        tags: [\n            \"Microsoft\",\n            \"Agent 365\",\n            \"Enterprise\",\n            \"Governance\",\n            \"Security\",\n            \"Copilot\"\n        ],\n        significance: \"major\",\n        provider: \"Microsoft\",\n        providerColor: \"#0078d4\",\n        url: \"https://www.microsoft.com/en-us/security/blog/2026/05/01/microsoft-agent-365-now-generally-available-expands-capabilities-and-integrations/\"\n    },\n    {\n        id: \"pentagon-ai-classified-deals\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 1,\n        title: \"Pentagon Clears 8 AI Companies for Classified Military Networks\",\n        summary: \"The US Department of Defense announced agreements with eight companies — OpenAI, Google, Microsoft, Nvidia, Amazon, SpaceX, Oracle, and Reflection — to deploy AI on its Impact Level 6 and Level 7 classified networks on May 1, 2026. The deals target warfighter decision-making and data synthesis, with all companies pledging not to use the technology for autonomous weapons or mass surveillance. Anthropic was excluded after the Trump administration objected to the company's insistence on safety guardrails governing AI use in warfare.\",\n        tags: [\n            \"OpenAI\",\n            \"Google\",\n            \"Microsoft\",\n            \"Pentagon\",\n            \"Defense\",\n            \"Policy\",\n            \"Regulation\"\n        ],\n        significance: \"major\",\n        provider: \"OpenAI\",\n        providerColor: \"#10a37f\",\n        url: \"https://www.washingtonpost.com/technology/2026/05/01/pentagon-ai-deals-microsoft-amazon-google-classified-military/\"\n    },\n    // ── Auto-updated 2026-05-18 (run 2) ──────────────────────────────────────\n    {\n        id: \"caisi-frontier-labs\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 5,\n        title: \"All Five Frontier AI Labs Now Under US Government Pre-Deployment Review\",\n        summary: \"The US Department of Commerce's Center for AI Standards and Innovation finalized pre-deployment evaluation agreements with Google DeepMind, Microsoft, and xAI on May 5, 2026, joining OpenAI and Anthropic in a program that has now completed more than 40 frontier model assessments. Under the agreements, every major model from these labs must undergo government safety and security evaluation before public release. The expansion marks the clearest signal yet that pre-deployment government review is becoming a baseline expectation for frontier AI development in the United States.\",\n        tags: [\n            \"Regulation\",\n            \"CAISI\",\n            \"Google\",\n            \"Microsoft\",\n            \"xAI\",\n            \"Safety\",\n            \"Policy\"\n        ],\n        significance: \"major\",\n        provider: \"Google\",\n        providerColor: \"#4285f4\",\n        url: \"https://www.cnbc.com/2026/05/05/ai-oversight-trump-google-microsoft-xai.html\"\n    },\n    {\n        id: \"claude-small-business\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 13,\n        title: \"Claude for Small Business — 15 Agentic Workflows Across Core Business Tools\",\n        summary: \"Anthropic launched Claude for Small Business on May 13, 2026, shipping 15 ready-to-run agentic workflows spanning finance, operations, sales, marketing, HR, and customer service, with native connectors for QuickBooks, PayPal, HubSpot, Canva, Docusign, Google Workspace, Microsoft 365, and Slack. The workflows automate recurring tasks including payroll planning, month-end close, invoice chasing, lead triage, contract review, and cash-flow monitoring. Existing Claude Team and Enterprise subscribers get access at no additional cost, with the agent reusing the user's existing permissions on each connected application.\",\n        tags: [\n            \"Anthropic\",\n            \"Claude\",\n            \"Agents\",\n            \"Small Business\",\n            \"QuickBooks\",\n            \"Automation\"\n        ],\n        significance: \"major\",\n        provider: \"Anthropic\",\n        providerColor: \"#d97706\",\n        url: \"https://www.anthropic.com/news/claude-for-small-business\"\n    },\n    {\n        id: \"anthropic-gates-foundation\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 14,\n        title: \"Anthropic and Gates Foundation Launch $200M Global Health and Education AI Initiative\",\n        summary: \"Anthropic and the Bill & Melinda Gates Foundation announced a $200 million, four-year partnership on May 14, 2026 to deploy Claude in global health, education, and agriculture programs serving low- and middle-income countries. The deal includes grant funding, Claude usage credits, and technical support, targeting disease response acceleration, evidence-based K-12 tutoring, and smallholder farming assistance in sub-Saharan Africa and India. The partnership is four times the size of OpenAI's $50 million Gates deal announced in January 2026.\",\n        tags: [\n            \"Anthropic\",\n            \"Claude\",\n            \"Gates Foundation\",\n            \"Global Health\",\n            \"Education\",\n            \"Partnership\"\n        ],\n        significance: \"notable\",\n        provider: \"Anthropic\",\n        providerColor: \"#d97706\",\n        url: \"https://www.anthropic.com/news/gates-foundation-partnership\"\n    },\n    {\n        id: \"gemini-3-5-flash-io2026\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 19,\n        title: \"Gemini 3.5 Flash — Google I/O 2026 Flagship Beats 3.1 Pro on Coding and Agents\",\n        summary: \"Google launched Gemini 3.5 Flash at Google I/O on May 19, 2026 as the first model in the Gemini 3.5 family, immediately becoming the default model in the Gemini app and AI Mode in Google Search. The model outperforms Gemini 3.1 Pro on coding and agentic benchmarks — Terminal-Bench 2.1 at 76.2%, MCP Atlas at 83.6%, CharXiv Reasoning at 84.2% — while running 4× faster in output tokens per second. API pricing is $1.50 per million input tokens and $9.00 per million output tokens, approximately 40% cheaper than Gemini 3.1 Pro. Gemini 3.5 Pro was previewed as coming in June 2026.\",\n        tags: [\n            \"Google\",\n            \"Gemini 3.5\",\n            \"Google I/O\",\n            \"Coding\",\n            \"Agents\",\n            \"Benchmark\"\n        ],\n        significance: \"major\",\n        provider: \"Google\",\n        providerColor: \"#4285f4\",\n        url: \"https://www.digit.in/features/general/google-io-2026-gemini-35-to-ai-smart-glasses-everything-that-was-announced.html\"\n    },\n    {\n        id: \"google-search-ai-mode-overhaul\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 19,\n        title: \"Google Search's Biggest Redesign in 25 Years — AI Agents and Generative UI\",\n        summary: \"Google unveiled a complete AI overhaul of Search at Google I/O on May 19, 2026, described as the biggest change to the search box in over 25 years. The new intelligent search box accepts text, images, files, videos, and Chrome tabs as inputs; agentic 'information agents' launching in summer 2026 will monitor the web continuously and alert users to changes. Generative UI, powered by Gemini 3.5 Flash, allows Search to dynamically produce custom interfaces, simulations, graphs, and mini-apps in response to queries. AI Mode already surpassed one billion monthly users with query volumes more than doubling every quarter since launch.\",\n        tags: [\n            \"Google\",\n            \"Search\",\n            \"AI Mode\",\n            \"Agents\",\n            \"Generative UI\",\n            \"Google I/O\",\n            \"Gemini\"\n        ],\n        significance: \"major\",\n        provider: \"Google\",\n        providerColor: \"#4285f4\",\n        url: \"https://blog.google/products-and-platforms/products/search/search-io-2026/\"\n    },\n    // ── Auto-updated 2026-05-20 ────────────────────────────────────────────\n    {\n        id: \"gemini-spark-agent-io2026\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 19,\n        title: \"Gemini Spark — Google's 24/7 AI Agent Launches at Google I/O 2026\",\n        summary: \"Google announced Gemini Spark at Google I/O on May 19, 2026 — a cloud-based AI agent that runs continuously in the background, reasoning across connected apps and taking actions on behalf of users. Spark integrates with Gmail, Docs, Uber, OpenTable, Lyft, Zillow, and dozens of third-party services, enabling autonomous multi-step workflows such as booking restaurants, tracking packages, and organizing calendar events. Beta access is included with the new Google AI Ultra subscription at $100 per month, rolling out first to trusted testers.\",\n        tags: [\n            \"Google\",\n            \"Gemini Spark\",\n            \"Google I/O\",\n            \"Agents\",\n            \"Automation\",\n            \"AI Ultra\"\n        ],\n        significance: \"major\",\n        provider: \"Google\",\n        providerColor: \"#4285f4\",\n        url: \"https://www.cnbc.com/2026/05/19/google-ai-ultra-gemini-spark-omni.html\"\n    },\n    {\n        id: \"gemini-omni-io2026\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 19,\n        title: \"Gemini Omni — Google's Unified Video-Image Generation Model Unveiled\",\n        summary: \"Google DeepMind CEO Demis Hassabis unveiled Gemini Omni at Google I/O 2026, a multimodal model that unifies text, image, and video generation in a single set of weights — the first top-tier AI system to do so. Omni supports conversational video editing via voice commands, allowing users to transform uploaded footage by adjusting characters, backgrounds, and framing in real time. The initial release, Gemini Omni Flash, is grounded in real-world knowledge via Google Search and is planned for launch in summer 2026.\",\n        tags: [\n            \"Google\",\n            \"Gemini Omni\",\n            \"Google I/O\",\n            \"Video Generation\",\n            \"Multimodal\",\n            \"DeepMind\"\n        ],\n        significance: \"major\",\n        provider: \"Google\",\n        providerColor: \"#4285f4\",\n        url: \"https://www.businesstoday.in/technology/artificial-intelligence/story/google-io-2026-google-unveils-gemini-omni-ai-video-editing-model-532350-2026-05-19\"\n    },\n    {\n        id: \"google-samsung-xr-glasses\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 19,\n        title: \"Google and Samsung Unveil Gemini-Powered Android XR Smart Glasses\",\n        summary: \"Google and Samsung revealed the first Android XR smart glasses at Google I/O 2026, with eyewear frames designed by Gentle Monster and Warby Parker for fall 2026 availability. The two-tier lineup includes audio-only glasses with cameras and microphones for all-day wear, and an optional in-lens display variant for private contextual information. Powered by Gemini, the glasses support live translation, navigation, calls, messaging, and real-time visual assistance, activated by voice or a tap on the frame.\",\n        tags: [\n            \"Google\",\n            \"Samsung\",\n            \"Android XR\",\n            \"Smart Glasses\",\n            \"Wearables\",\n            \"Gemini\",\n            \"Google I/O\"\n        ],\n        significance: \"notable\",\n        provider: \"Google\",\n        providerColor: \"#4285f4\",\n        url: \"https://www.techradar.com/news/live/google-io-2026-live\"\n    },\n    {\n        id: \"google-gemma-4\",\n        date: \"Apr 2026\",\n        dateNum: 202604,\n        dateDay: 2,\n        title: \"Gemma 4 — Google's Most Capable Open-Source Model Family\",\n        summary: \"Google released Gemma 4 on April 2, 2026 under Apache 2.0, in four sizes (2B to 31B parameters) with 256K context windows, native vision and audio processing, and support for 140+ languages. The 31B dense flagship targets advanced reasoning, multi-step planning, agentic workflows, and offline code generation — available on Hugging Face, Kaggle, and Google AI Studio.\",\n        tags: [\n            \"Google\",\n            \"Gemma\",\n            \"Open Source\",\n            \"Multimodal\",\n            \"Reasoning\"\n        ],\n        significance: \"major\",\n        provider: \"Google\",\n        providerColor: \"#4285f4\",\n        url: \"https://blog.google/innovation-and-ai/technology/developers-tools/gemma-4/\"\n    },\n    {\n        id: \"cohere-aleph-alpha-merger\",\n        date: \"Apr 2026\",\n        dateNum: 202604,\n        dateDay: 24,\n        title: \"Cohere Merges With Aleph Alpha — $20B Transatlantic AI Company Formed\",\n        summary: \"Canadian AI firm Cohere and Germany's Aleph Alpha announced a merger on April 24, 2026, forming a transatlantic enterprise AI company valued at roughly $20 billion. The deal, anchored by a €500 million commitment from Schwarz Group (Lidl and Kaufland's parent), received backing from both the Canadian and German governments. Cohere CEO Aidan Gomez will lead the combined company, which will operate under the Cohere name and compete directly with US frontier labs for European and sovereign AI contracts.\",\n        tags: [\n            \"Cohere\",\n            \"Aleph Alpha\",\n            \"Merger\",\n            \"Europe\",\n            \"Enterprise AI\",\n            \"Sovereign AI\"\n        ],\n        significance: \"notable\",\n        provider: \"Cohere\",\n        providerColor: \"#39c5cf\",\n        url: \"https://techcrunch.com/2026/04/25/why-cohere-is-merging-with-aleph-alpha/\"\n    },\n    {\n        id: \"deepseek-v4\",\n        date: \"Apr 2026\",\n        dateNum: 202604,\n        dateDay: 24,\n        title: \"DeepSeek V4 — 1.6T-Parameter MoE, 80.6% SWE-bench Verified\",\n        summary: \"DeepSeek released V4-Pro and V4-Flash on April 24, 2026 under MIT license. V4-Pro packs 1.6T total parameters with 49B active via mixture-of-experts, a 1M-token context window, and scored 80.6% on SWE-bench Verified — matching frontier closed-source models. Weights are on Hugging Face; V4-Flash (284B total, 13B active) targets cost-efficient inference.\",\n        tags: [\n            \"DeepSeek\",\n            \"V4\",\n            \"Open Source\",\n            \"MoE\",\n            \"Coding\",\n            \"SWE-bench\"\n        ],\n        significance: \"major\",\n        provider: \"DeepSeek\",\n        providerColor: \"#1a73e8\",\n        url: \"https://huggingface.co/deepseek-ai/DeepSeek-V4-Pro\"\n    },\n    {\n        id: \"anthropic-dreaming-agents\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 6,\n        title: \"Anthropic Dreaming — Claude Agents Now Self-Improve Between Sessions\",\n        summary: \"Anthropic launched Dreaming on May 6, 2026, a scheduled maintenance layer that reviews an agent's past sessions, extracts patterns across them, and curates memory stores so agents improve over time without modifying model weights. Supported on Claude Opus 4.7 and Sonnet 4.6, Dreaming feeds up to 100 past sessions into a single 'dream' and surfaces recurring mistakes, convergent workflows, and team-wide preferences. Early adopter Harvey (legal AI) reported a 6× increase in task completion rates after implementing the feature; access is currently gated behind a request form.\",\n        tags: [\n            \"Anthropic\",\n            \"Claude\",\n            \"Dreaming\",\n            \"Agents\",\n            \"Memory\",\n            \"Self-Improvement\"\n        ],\n        significance: \"major\",\n        provider: \"Anthropic\",\n        providerColor: \"#d97706\",\n        url: \"https://venturebeat.com/technology/anthropic-introduces-dreaming-a-system-that-lets-ai-agents-learn-from-their-own-mistakes\"\n    },\n    {\n        id: \"anthropic-managed-agents-sandboxes-mcp-tunnels\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 19,\n        title: \"Anthropic Launches Self-Hosted Sandboxes and Encrypted MCP Tunnels for Claude Agents\",\n        summary: \"Announced at Code with Claude London (May 19–20, 2026), Anthropic released self-hosted sandboxes in public beta and MCP tunnels in research preview for Claude Managed Agents. Self-hosted sandboxes let enterprises run agent tool execution on their own infrastructure — or via Cloudflare, Daytona, Modal, or Vercel — while Anthropic retains orchestration. MCP tunnels provide end-to-end encrypted access to private MCP servers with no inbound firewall rules required, enabling agents to reach internal databases and APIs without public exposure.\",\n        tags: [\n            \"Anthropic\",\n            \"Claude\",\n            \"Managed Agents\",\n            \"MCP\",\n            \"Agent Infrastructure\",\n            \"Security\"\n        ],\n        significance: \"major\",\n        provider: \"Anthropic\",\n        providerColor: \"#d97706\",\n        url: \"https://claude.com/blog/claude-managed-agents-updates\"\n    },\n    {\n        id: \"recursive-superintelligence-650m-launch\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 13,\n        title: \"Recursive Superintelligence Exits Stealth with $650M at $4.65B Valuation\",\n        summary: \"UK-based startup Recursive Superintelligence exited stealth on May 13, 2026 with $650 million raised at a $4.65 billion valuation, backed by GV (Alphabet's VC arm), Greycroft, Nvidia, and AMD. Co-founded by ex-Salesforce chief scientist Richard Socher and UCL/DeepMind professor Tim Rocktäschel, the 30-person team is building AI systems that autonomously improve themselves in recursive loops — starting with AI-driven AI research. A Level 1 autonomous training system is targeted for public launch in mid-2026.\",\n        tags: [\n            \"Recursive Superintelligence\",\n            \"Funding\",\n            \"Self-Improving AI\",\n            \"Stealth Launch\",\n            \"UK AI\"\n        ],\n        significance: \"major\",\n        provider: \"Recursive Superintelligence\",\n        providerColor: \"#6d28d9\",\n        url: \"https://tech.eu/2026/05/13/recursive-superintelligence-emerges-from-stealth-with-650m-raise/\"\n    },\n    {\n        id: \"eu-ai-act-omnibus-simplification-may-2026\",\n        date: \"May 2026\",\n        dateNum: 202605,\n        dateDay: 7,\n        title: \"EU Parliament and Council Agree AI Act Omnibus Simplification\",\n        summary: \"The European Parliament and Council reached a provisional agreement on May 7, 2026 on the Digital Omnibus package, delaying high-risk AI compliance deadlines — standalone systems to December 2027, product-embedded systems to August 2028 — and reducing administrative burdens for SMEs and mid-caps. New prohibitions on non-consensual intimate AI imagery and CSAM generation take effect December 2026. The deal also broadens permissions for sensitive data use in bias mitigation; formal adoption is expected before the original August 2, 2026 deadline.\",\n        tags: [\n            \"EU\",\n            \"Regulation\",\n            \"AI Act\",\n            \"Policy\",\n            \"Compliance\",\n            \"Digital Omnibus\"\n        ],\n        significance: \"major\",\n        provider: \"European Union\",\n        providerColor: \"#003399\",\n        url: \"https://www.consilium.europa.eu/en/press/press-releases/2026/05/07/artificial-intelligence-council-and-parliament-agree-to-simplify-and-streamline-rules/\"\n    }\n];\n// ── Derived exports ────────────────────────────────────────────────────────\n/** Alias kept for component compatibility. */ const NEWS_ITEMS = AI_NEWS;\nconst NEWS_TAGS = Array.from(new Set(AI_NEWS.flatMap((item)=>item.tags))).sort();\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/lib/newsData.ts\n");

